import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    # {Design an algorithm that uses a dynamic score that adjusts based on the urgency of time windows and proximity to clusters of customers, incorporating a cooldown mechanism to avoid repeatedly visiting clustered areas.}

    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    best_score = float('inf')
    best_node = None
    cooldown_factor = 0.5  # Factor to increase score for already visited areas to avoid clustering

    for i, customer in enumerate(unvisited_customers):
        earliest, latest = time_windows[i]
        travel_to_customer = travel_time(cur_truck_pos, customer)
        arrival_time = current_time + travel_to_customer

        # Dynamic penalty based on how close to the time window deadline
        if arrival_time < earliest:
            penalty = (earliest - arrival_time) ** 2
        else:
            penalty = 0

        if arrival_time > latest:
            penalty += (arrival_time - latest) * 15  # Larger penalty for missing the window

        # Calculate a score incorporating penalties and travel time
        score = travel_to_customer + penalty

        # Check vicinity for clusters and apply cooldown to previously visited regions
        cluster_effect = 0
        for other_truck in all_truck_pos:
            cluster_effect += 1 / (np.linalg.norm(customer - other_truck) + 1)  # Attractive force to less clustered customers
        score += cluster_effect * cooldown_factor

        if score < best_score:
            best_score = score
            best_node = i

    return best_node
